import * as d3 from 'd3';

export interface RadarChartDataPoint {
  name: string;
  values: { [axisName: string]: number };
}

export interface RadarChartOptions {
  data?: RadarChartDataPoint[];
  width?: number;
  height?: number;
  responsive?: boolean;
  axes?: string[];
  levels?: number;
  maxValue?: number;
  labelFactor?: number;
  wrapWidth?: number;
  opacityArea?: number;
  dotRadius?: number;
  opacityCircles?: number;
  strokeWidth?: number;
}

export class RadarChart {
  private _container: HTMLElement;
  private _data: RadarChartDataPoint[];
  private _width: number;
  private _height: number;
  private _responsive: boolean;
  private _axes: string[];
  private _levels: number;
  private _maxValue: number;
  private _labelFactor: number;
  private _wrapWidth: number;
  private _opacityArea: number;
  private _dotRadius: number;
  private _opacityCircles: number;
  private _strokeWidth: number;
  private _svg: d3.Selection<SVGSVGElement, unknown, null, undefined> | null = null;
  private _resizeObserver: ResizeObserver | null = null;

  // BNPP theme colors (greens)
  private readonly colors = ['#008859', '#007a50', '#00a86b', '#00c17c', '#33cc94'];

  constructor(container: HTMLElement | string, options?: RadarChartOptions) {
    // Support both HTMLElement and string (element ID)
    if (typeof container === 'string') {
      const element = document.getElementById(container);
      if (!element) {
        throw new Error(`Container with id "${container}" not found`);
      }
      this._container = element;
    } else {
      this._container = container;
    }

    const opts = options || {};

    // Use provided data or default dummy data
    this._data = opts.data || this.getDefaultData();
    this._width = opts.width || 500;
    this._height = opts.height || 500;
    this._responsive = opts.responsive !== undefined ? opts.responsive : false;

    // Extract axes from data if not provided
    if (opts.axes && opts.axes.length > 0) {
      this._axes = opts.axes;
    } else if (this._data.length > 0) {
      this._axes = Object.keys(this._data[0].values);
    } else {
      this._axes = [];
    }

    this._levels = opts.levels || 5;
    this._maxValue = opts.maxValue || 100;
    this._labelFactor = opts.labelFactor || 1.25;
    this._wrapWidth = opts.wrapWidth || 60;
    this._opacityArea = opts.opacityArea !== undefined ? opts.opacityArea : 0.35;
    this._dotRadius = opts.dotRadius || 4;
    this._opacityCircles = opts.opacityCircles !== undefined ? opts.opacityCircles : 0.1;
    this._strokeWidth = opts.strokeWidth || 2;
  }

  /**
   * Generate default dummy data
   */
  private getDefaultData(): RadarChartDataPoint[] {
    return [
      {
        name: 'Project Alpha',
        values: {
          'Completion %': 85,
          'Team Morale': 75,
          'Customer Satisfaction': 90,
          'Budget Utilization %': 70,
          'Process Adherence %': 80,
        },
      },
      {
        name: 'Project Beta',
        values: {
          'Completion %': 70,
          'Team Morale': 85,
          'Customer Satisfaction': 75,
          'Budget Utilization %': 90,
          'Process Adherence %': 65,
        },
      },
    ];
  }

  /**
   * Render the radar chart
   */
  render(): void {
    // Clear container
    this._container.innerHTML = '';

    // Clean up existing resize observer
    if (this._resizeObserver) {
      this._resizeObserver.disconnect();
      this._resizeObserver = null;
    }

    // Validate data
    if (!this._data || this._data.length === 0) {
      console.warn('No data provided for RadarChart');
      return;
    }

    if (!this._axes || this._axes.length === 0) {
      console.warn('No axes defined for RadarChart');
      return;
    }

    // Calculate dimensions
    const margin = { top: 50, right: 80, bottom: 50, left: 80 };
    const radius = Math.min(this._width / 2 - margin.left, this._height / 2 - margin.top);
    const angleSlice = (Math.PI * 2) / this._axes.length;

    // Create SVG
    this._svg = d3
      .select(this._container)
      .append('svg')
      .attr('viewBox', `0 0 ${this._width} ${this._height}`)
      .style('display', 'block')
      .style('margin', '0 auto');

    // Handle responsive vs fixed dimensions
    if (this._responsive) {
      this._svg
        .style('width', '100%')
        .style('height', '100%')
        .attr('preserveAspectRatio', 'xMidYMid meet');

      // Set up resize observer for true responsiveness
      const self = this;
      this._resizeObserver = new ResizeObserver(() => {
        if (self._svg) {
          self._svg
            .style('width', '100%')
            .style('height', '100%');
        }
      });
      this._resizeObserver.observe(this._container);
    } else {
      this._svg
        .attr('width', this._width)
        .attr('height', this._height);
    }

    // Create main group centered in the SVG
    const g = this._svg
      .append('g')
      .attr('transform', `translate(${this._width / 2},${this._height / 2})`);

    // Circular grid
    const axisGrid = g.append('g').attr('class', 'axisWrapper');

    // Draw the circular grid lines (background)
    axisGrid
      .selectAll('.levels')
      .data(d3.range(1, this._levels + 1).reverse())
      .enter()
      .append('circle')
      .attr('class', 'gridCircle')
      .attr('r', (d) => (radius / this._levels) * d)
      .style('fill', '#CDCDCD')
      .style('stroke', '#CDCDCD')
      .style('fill-opacity', this._opacityCircles)
      .style('filter', 'url(#glow)');

    // Text indicating the percentage levels
    axisGrid
      .selectAll('.axisLabel')
      .data(d3.range(1, this._levels + 1).reverse())
      .enter()
      .append('text')
      .attr('class', 'axisLabel')
      .attr('x', 4)
      .attr('y', (d) => -(d * radius) / this._levels)
      .attr('dy', '0.4em')
      .style('font-size', '10px')
      .style('fill', '#737373')
      .text((d) => ((this._maxValue * d) / this._levels).toFixed(0));

    // Draw the axes
    const axis = axisGrid
      .selectAll('.axis')
      .data(this._axes)
      .enter()
      .append('g')
      .attr('class', 'axis');

    // Draw axis lines
    axis
      .append('line')
      .attr('x1', 0)
      .attr('y1', 0)
      .attr('x2', (_d, i) => radius * Math.cos(angleSlice * i - Math.PI / 2))
      .attr('y2', (_d, i) => radius * Math.sin(angleSlice * i - Math.PI / 2))
      .style('stroke', '#999')
      .style('stroke-width', '2px');

    // Draw axis labels
    axis
      .append('text')
      .attr('class', 'legend')
      .style('font-size', '11px')
      .style('font-weight', 'bold')
      .style('fill', '#333')
      .attr('text-anchor', 'middle')
      .attr('dy', '0.35em')
      .attr('x', (_d, i) => radius * this._labelFactor * Math.cos(angleSlice * i - Math.PI / 2))
      .attr('y', (_d, i) => radius * this._labelFactor * Math.sin(angleSlice * i - Math.PI / 2))
      .text((d) => d)
      .call(this.wrap, this._wrapWidth);

    // Radial scale
    const rScale = d3.scaleLinear().range([0, radius]).domain([0, this._maxValue]);

    // Function to convert data to coordinates
    const radarLine = d3
      .lineRadial<{ axis: string; value: number }>()
      .curve(d3.curveLinearClosed)
      .radius((d) => rScale(d.value))
      .angle((_d, i) => i * angleSlice);

    // Create a wrapper for the blobs
    const blobWrapper = g
      .selectAll('.radarWrapper')
      .data(this._data)
      .enter()
      .append('g')
      .attr('class', 'radarWrapper');

    // Append the backgrounds
    blobWrapper
      .append('path')
      .attr('class', 'radarArea')
      .attr('d', (d) => {
        const dataPoints = this._axes.map((axis) => ({
          axis,
          value: Math.min(d.values[axis] || 0, this._maxValue),
        }));
        return radarLine(dataPoints);
      })
      .style('fill', (_d, i) => this.colors[i % this.colors.length])
      .style('fill-opacity', this._opacityArea)
      .on('mouseover', function () {
        // Dim all other blobs
        d3.selectAll('.radarArea')
          .transition()
          .duration(200)
          .style('fill-opacity', 0.1);
        // Highlight this one
        d3.select(this)
          .transition()
          .duration(200)
          .style('fill-opacity', 0.7);
      })
      .on('mouseout', () => {
        // Restore opacity
        d3.selectAll('.radarArea')
          .transition()
          .duration(200)
          .style('fill-opacity', this._opacityArea);
      });

    // Create the outlines
    blobWrapper
      .append('path')
      .attr('class', 'radarStroke')
      .attr('d', (d) => {
        const dataPoints = this._axes.map((axis) => ({
          axis,
          value: Math.min(d.values[axis] || 0, this._maxValue),
        }));
        return radarLine(dataPoints);
      })
      .style('stroke-width', this._strokeWidth + 'px')
      .style('stroke', (_d, i) => this.colors[i % this.colors.length])
      .style('fill', 'none')
      .style('filter', 'url(#glow)');

    // Append the circles
    blobWrapper
      .selectAll('.radarCircle')
      .data((d, seriesIndex) =>
        this._axes.map((axis) => ({
          axis,
          value: Math.min(d.values[axis] || 0, this._maxValue),
          name: d.name,
          seriesIndex,
        }))
      )
      .enter()
      .append('circle')
      .attr('class', 'radarCircle')
      .attr('r', this._dotRadius)
      .attr(
        'cx',
        (_d, i) =>
          rScale(_d.value) * Math.cos(angleSlice * i - Math.PI / 2)
      )
      .attr(
        'cy',
        (_d, i) =>
          rScale(_d.value) * Math.sin(angleSlice * i - Math.PI / 2)
      )
      .style('fill', (d) => this.colors[d.seriesIndex % this.colors.length])
      .style('fill-opacity', 0.8);

    // Add legend
    const legend = this._svg
      .append('g')
      .attr('class', 'legend')
      .attr('transform', `translate(${this._width - margin.right + 10}, ${margin.top})`);

    const legendItems = legend
      .selectAll('.legendItem')
      .data(this._data)
      .enter()
      .append('g')
      .attr('class', 'legendItem')
      .attr('transform', (_d, i) => `translate(0, ${i * 25})`)
      .style('cursor', 'pointer')
      .on('mouseover', (_event, d) => {
        const datasetName = d.name;
        // Highlight the corresponding blob
        d3.selectAll<SVGPathElement, RadarChartDataPoint>('.radarArea')
          .transition()
          .duration(200)
          .style('fill-opacity', function (data) {
            return data.name === datasetName ? 0.7 : 0.1;
          });
      })
      .on('mouseout', () => {
        // Restore opacity
        d3.selectAll('.radarArea')
          .transition()
          .duration(200)
          .style('fill-opacity', this._opacityArea);
      });

    // Legend color boxes
    legendItems
      .append('rect')
      .attr('width', 15)
      .attr('height', 15)
      .style('fill', (_d, i) => this.colors[i % this.colors.length]);

    // Legend text
    legendItems
      .append('text')
      .attr('x', 20)
      .attr('y', 12)
      .style('font-size', '12px')
      .style('fill', '#333')
      .text((d) => d.name);

    // Add glow filter for better visual effect
    const defs = this._svg.append('defs');
    const filter = defs.append('filter').attr('id', 'glow');
    filter
      .append('feGaussianBlur')
      .attr('stdDeviation', '2.5')
      .attr('result', 'coloredBlur');
    const feMerge = filter.append('feMerge');
    feMerge.append('feMergeNode').attr('in', 'coloredBlur');
    feMerge.append('feMergeNode').attr('in', 'SourceGraphic');
  }

  /**
   * Wrap text into multiple lines
   */
  private wrap(text: d3.Selection<SVGTextElement, string, SVGGElement, unknown>, width: number): void {
    text.each(function () {
      const text = d3.select(this);
      const words = text.text().split(/\s+/).reverse();
      let word: string | undefined;
      let line: string[] = [];
      let lineNumber = 0;
      const lineHeight = 1.4; // ems
      const y = text.attr('y');
      const x = text.attr('x');
      const dy = parseFloat(text.attr('dy') || '0');
      let tspan = text
        .text(null)
        .append('tspan')
        .attr('x', x)
        .attr('y', y)
        .attr('dy', dy + 'em');

      while ((word = words.pop())) {
        line.push(word);
        tspan.text(line.join(' '));
        if (tspan.node()!.getComputedTextLength() > width) {
          line.pop();
          tspan.text(line.join(' '));
          line = [word];
          tspan = text
            .append('tspan')
            .attr('x', x)
            .attr('y', y)
            .attr('dy', ++lineNumber * lineHeight + dy + 'em')
            .text(word);
        }
      }
    });
  }

  /**
   * Set new data and re-render
   */
  setData(data: RadarChartDataPoint[], axes?: string[]): void {
    this._data = data;

    if (axes && axes.length > 0) {
      this._axes = axes;
    } else if (data.length > 0) {
      this._axes = Object.keys(data[0].values);
    }

    this.render();
  }

  /**
   * Update dimensions
   */
  setDimensions(width: number, height: number): void {
    this._width = width;
    this._height = height;
    if (this._svg) {
      this.render();
    }
  }

  /**
   * Enable or disable responsive mode
   */
  setResponsive(responsive: boolean): void {
    this._responsive = responsive;
    this.render();
  }

  /**
   * Get current dimensions
   */
  getDimensions(): { width: number; height: number } {
    return { width: this._width, height: this._height };
  }

  /**
   * Get current axes
   */
  getAxes(): string[] {
    return [...this._axes];
  }

  /**
   * Destroy the chart and clean up
   */
  destroy(): void {
    // Clean up resize observer
    if (this._resizeObserver) {
      this._resizeObserver.disconnect();
      this._resizeObserver = null;
    }

    // Remove SVG
    if (this._svg) {
      this._svg.remove();
      this._svg = null;
    }

    // Clear container
    this._container.innerHTML = '';
  }
}
