import * as d3 from 'd3';

export interface CirclePackingNode {
  name: string;
  value?: number;
  children?: CirclePackingNode[];
}

export interface CirclePackingChartOptions {
  data?: CirclePackingNode;
  width?: number;
  height?: number;
  responsive?: boolean;
}

export class CirclePackingChart {
  private _container: HTMLElement;
  private _data: CirclePackingNode;
  private _width: number;
  private _height: number;
  private _responsive: boolean;
  private _svg: d3.Selection<SVGSVGElement, unknown, null, undefined> | null = null;
  private _resizeObserver: ResizeObserver | null = null;

  constructor(container: HTMLElement | string, options?: CirclePackingChartOptions | CirclePackingNode) {
    // Support both HTMLElement and string (element ID)
    if (typeof container === 'string') {
      const element = document.getElementById(container);
      if (!element) {
        throw new Error(`Container with id "${container}" not found`);
      }
      this._container = element;
    } else {
      this._container = container;
    }

    // Handle backward compatibility: if options has 'name' property, it's CirclePackingNode (old API)
    let opts: CirclePackingChartOptions = {};
    if (options && 'name' in options) {
      // Old API: second parameter is data
      opts = { data: options as CirclePackingNode };
    } else {
      // New API: second parameter is options object
      opts = (options as CirclePackingChartOptions) || {};
    }

    // Use provided data or default dummy data
    this._data = opts.data || this.getDefaultData();
    this._width = opts.width || 928;
    this._height = opts.height || 928;
    this._responsive = opts.responsive !== undefined ? opts.responsive : false;
  }

  /**
   * Generate default hierarchical dummy data
   */
  private getDefaultData(): CirclePackingNode {
    return {
      name: 'root',
      children: [
        {
          name: 'Analytics',
          children: [
            { name: 'Dashboard', value: 3812 },
            { name: 'Reports', value: 6714 },
            { name: 'Metrics', value: 743 },
            { name: 'Visualization', value: 3534 },
          ],
        },
        {
          name: 'Data',
          children: [
            {
              name: 'Database',
              children: [
                { name: 'SQL', value: 721 },
                { name: 'NoSQL', value: 4294 },
                { name: 'Cache', value: 1314 },
              ],
            },
            {
              name: 'Processing',
              children: [
                { name: 'ETL', value: 2220 },
                { name: 'Transformation', value: 3201 },
                { name: 'Validation', value: 1759 },
              ],
            },
            { name: 'Storage', value: 2165 },
          ],
        },
        {
          name: 'API',
          children: [
            { name: 'REST', value: 8833 },
            { name: 'GraphQL', value: 1732 },
            {
              name: 'Authentication',
              children: [
                { name: 'OAuth', value: 3623 },
                { name: 'JWT', value: 2042 },
                { name: 'Session', value: 1041 },
              ],
            },
          ],
        },
        {
          name: 'UI',
          children: [
            {
              name: 'Components',
              children: [
                { name: 'Buttons', value: 1983 },
                { name: 'Forms', value: 2047 },
                { name: 'Tables', value: 1375 },
                { name: 'Modals', value: 1610 },
              ],
            },
            {
              name: 'Layouts',
              children: [
                { name: 'Grid', value: 1842 },
                { name: 'Flex', value: 2213 },
              ],
            },
            { name: 'Themes', value: 1302 },
          ],
        },
      ],
    };
  }

  /**
   * Render the circle packing chart
   */
  render(): void {
    // Clear container
    this._container.innerHTML = '';

    // Clean up existing resize observer
    if (this._resizeObserver) {
      this._resizeObserver.disconnect();
      this._resizeObserver = null;
    }

    // Capture this for use in nested functions
    const self = this;

    // Create color scale
    const color = d3
      .scaleLinear<string>()
      .domain([0, 5])
      .range(['hsl(152, 80%, 80%)', 'hsl(228, 30%, 40%)'])
      .interpolate(d3.interpolateHcl);

    // Compute the layout
    const pack = (data: CirclePackingNode) => {
      return d3
        .pack<CirclePackingNode>()
        .size([self._width, self._height])
        .padding(3)(
        d3
          .hierarchy(data)
          .sum((d) => d.value || 0)
          .sort((a, b) => (b.value || 0) - (a.value || 0))
      );
    };

    const root = pack(this._data);
    let focus = root;
    let view: [number, number, number];

    // Create SVG
    this._svg = d3
      .select(this._container)
      .append('svg')
      .attr('viewBox', `-${self._width / 2} -${self._height / 2} ${self._width} ${self._height}`)
      .style('display', 'block')
      .style('margin', '0 auto')
      .style('background', '#fff')
      .style('cursor', 'pointer')
      .on('click', (event) => zoom(event, root));

    // Handle responsive vs fixed dimensions
    if (self._responsive) {
      this._svg
        .style('width', '100%')
        .style('height', '100%')
        .attr('preserveAspectRatio', 'xMidYMid meet');

      // Set up resize observer for true responsiveness
      this._resizeObserver = new ResizeObserver(() => {
        if (self._svg) {
          self._svg
            .style('width', '100%')
            .style('height', '100%');
        }
      });
      this._resizeObserver.observe(this._container);
    } else {
      this._svg
        .attr('width', self._width)
        .attr('height', self._height);
    }

    // Create nodes
    const node = this._svg
      .append('g')
      .selectAll('circle')
      .data(root.descendants().slice(1))
      .join('circle')
      .attr('fill', (d) => (d.children ? color(d.depth) : 'white'))
      .attr('stroke', (d) => (d.children ? 'none' : '#999'))
      .attr('stroke-width', 1.5)
      .attr('pointer-events', (d) => (!d.children ? 'none' : null))
      .on('mouseover', function () {
        d3.select(this).attr('stroke', '#000').attr('stroke-width', 2);
      })
      .on('mouseout', function (event, d) {
        d3.select(this)
          .attr('stroke', d.children ? 'none' : '#999')
          .attr('stroke-width', 1.5);
      })
      .on('click', (event, d) => {
        if (focus !== d) {
          zoom(event, d);
          event.stopPropagation();
        }
      });

    // Create labels with dynamic sizing based on depth
    const label = this._svg
      .append('g')
      .attr('pointer-events', 'none')
      .attr('text-anchor', 'middle')
      .selectAll('text')
      .data(root.descendants())
      .join('text')
      .style('fill-opacity', (d) => (d.parent === root ? 1 : 0))
      .style('display', (d) => (d.parent === root ? 'inline' : 'none'))
      .style('font-family', 'sans-serif')
      .style('font-size', (d) => {
        // Dynamic font size based on depth level
        if (d.depth === 0) return '32px'; // Root (rarely visible)
        if (d.depth === 1) return '28px'; // First level (EMEA, APAC, AMER)
        if (d.depth === 2) return '20px'; // Second level (Sectors)
        if (d.depth === 3) return '16px'; // Third level (Teams)
        return '14px'; // Fourth level and beyond (Sub-teams)
      })
      .style('font-weight', (d) => {
        // Bold for top levels
        if (d.depth <= 2) return 'bold';
        return 'normal';
      })
      .style('fill', (d) => {
        // Better contrast for readability
        if (d.depth <= 2) return '#ffffff';
        return '#333333';
      })
      .style('text-shadow', (d) => {
        // Add text shadow for top levels for better readability
        if (d.depth <= 2) return '0 1px 3px rgba(0,0,0,0.5), 0 0 10px rgba(0,0,0,0.3)';
        return 'none';
      })
      .text((d) => d.data.name);

    // Initialize the view
    zoomTo([root.x, root.y, root.r * 2]);

    function zoomTo(v: [number, number, number]) {
      const k = self._width / v[2];

      view = v;

      label.attr('transform', (d) => `translate(${(d.x - v[0]) * k},${(d.y - v[1]) * k})`);
      node.attr('transform', (d) => `translate(${(d.x - v[0]) * k},${(d.y - v[1]) * k})`);
      node.attr('r', (d) => d.r * k);
    }

    const zoom = (
      event: MouseEvent,
      d: d3.HierarchyCircularNode<CirclePackingNode>
    ) => {
      const altKeyPressed = event?.altKey;
      const duration = altKeyPressed ? 7500 : 750;

      focus = d;

      const transition = self._svg!
        .transition()
        .duration(duration)
        .tween('zoom', () => {
          const i = d3.interpolateZoom(view, [focus.x, focus.y, focus.r * 2]);
          return (t: number) => zoomTo(i(t));
        });

      label
        .filter(function (d) {
          return d.parent === focus || (this as SVGTextElement).style.display === 'inline';
        })
        .transition(transition as any)
        .style('fill-opacity', (d) => (d.parent === focus ? 1 : 0))
        .on('start', function (d) {
          if (d.parent === focus) (this as SVGTextElement).style.display = 'inline';
        })
        .on('end', function (d) {
          if (d.parent !== focus) (this as SVGTextElement).style.display = 'none';
        });
    };
  }

  /**
   * Set new data and re-render
   */
  setData(data: CirclePackingNode): void {
    this._data = data;
    this.render();
  }

  /**
   * Update dimensions
   */
  setDimensions(width: number, height: number): void {
    this._width = width;
    this._height = height;
    if (this._svg) {
      this.render();
    }
  }

  /**
   * Enable or disable responsive mode
   */
  setResponsive(responsive: boolean): void {
    this._responsive = responsive;
    this.render();
  }

  /**
   * Get current dimensions
   */
  getDimensions(): { width: number; height: number } {
    return { width: this._width, height: this._height };
  }

  /**
   * Destroy the chart and clean up
   */
  destroy(): void {
    // Clean up resize observer
    if (this._resizeObserver) {
      this._resizeObserver.disconnect();
      this._resizeObserver = null;
    }

    // Remove SVG
    if (this._svg) {
      this._svg.remove();
      this._svg = null;
    }

    // Clear container
    this._container.innerHTML = '';
  }
}
