import * as d3 from 'd3';

export interface BarChartData {
  label: string;
  value: number;
}

export class BarChart {
  private _container: HTMLElement;
  private _data: BarChartData[];
  private _width: number;
  private _height: number;

  constructor(containerId: string, data: BarChartData[]) {
    const element = document.getElementById(containerId);
    if (!element) {
      throw new Error(`Container with id "${containerId}" not found`);
    }
    this._container = element;
    this._data = data;
    this._width = 600;
    this._height = 400;
  }

  render(): void {
    // Clear container
    this._container.innerHTML = '';

    // Create SVG
    const svg = d3
      .select(this._container)
      .append('svg')
      .attr('width', this._width)
      .attr('height', this._height);

    // Set up scales
    const xScale = d3
      .scaleBand()
      .domain(this._data.map((d) => d.label))
      .range([50, this._width - 50])
      .padding(0.2);

    const yScale = d3
      .scaleLinear()
      .domain([0, d3.max(this._data, (d) => d.value) || 100])
      .range([this._height - 50, 50]);

    // Draw bars
    svg
      .selectAll('rect')
      .data(this._data)
      .enter()
      .append('rect')
      .attr('x', (d) => xScale(d.label) || 0)
      .attr('y', (d) => yScale(d.value))
      .attr('width', xScale.bandwidth())
      .attr('height', (d) => this._height - 50 - yScale(d.value))
      .attr('fill', '#4CAF50');

    // Add X axis
    svg
      .append('g')
      .attr('transform', `translate(0,${this._height - 50})`)
      .call(d3.axisBottom(xScale));

    // Add Y axis
    svg.append('g').attr('transform', 'translate(50,0)').call(d3.axisLeft(yScale));
  }
}
